import {
  Bell,
  Bike,
  LayoutDashboard,
  LogOut,
  Map,
  MessageCircle,
  Moon,
  Package,
  Settings as SettingsIcon,
  ShoppingBag,
  Store,
  Sun,
  TrendingDown,
  TrendingUp,
  Users,
  Image,
} from "lucide-react";
import { useEffect, useState } from "react";
import { Toaster } from "react-hot-toast";
import {
  Link,
  Navigate,
  Route,
  BrowserRouter as Router,
  Routes,
  useLocation,
  useNavigate,
} from "react-router-dom";
import "./App.css";
import { AuthProvider, useAuth } from "./context/AuthContext";
import { useAdminNotifications } from "./hooks/useAdminNotifications";
import Cities from "./pages/Cities";
import Customers from "./pages/Customers";
import Login from "./pages/Login";
import Notifications from "./pages/Notifications";
import Orders from "./pages/Orders";
import Products from "./pages/Products";
import Riders from "./pages/Riders";
import Settings from "./pages/Settings";
import Shops from "./pages/Shops";
import Banners from "./pages/Banners";
import Chats from "./pages/Chats";
import CustomOrders from "./pages/CustomOrders";
import Rides from "./pages/Rides";
import { adminService } from "./services/adminService";

const Sidebar = () => {
  const location = useLocation();
  const { logout } = useAuth();

  const navItems = [
    { path: "/", label: "Overview", icon: LayoutDashboard },
    { path: "/notifications", label: "Notifications", icon: Bell },
    { path: "/chats", label: "Chats", icon: MessageCircle },
    { path: "/cities", label: "Cities", icon: Map },
    { path: "/orders", label: "Orders", icon: ShoppingBag },
    { path: "/custom-orders", label: "Custom Orders", icon: Package },
    { path: "/rides", label: "Rides & Parcels", icon: Bike },
    { path: "/products", label: "Products", icon: Package },
    { path: "/customers", label: "Customers", icon: Users },
    { path: "/riders", label: "Riders", icon: Bike },
    { path: "/shops", label: "Shops", icon: Store },
    { path: "/banners", label: "Banners", icon: Image },
    { path: "/settings", label: "Settings", icon: SettingsIcon },
  ];

  return (
    <aside className="sidebar">
      <div className="sidebar-header">
        <div className="logo-circle">
          <ShoppingBag size={24} />
        </div>
        <div className="logo-text">ClickDeliver</div>
      </div>
      <nav className="nav-menu">
        {navItems.map((item) => (
          <Link
            key={item.path}
            to={item.path}
            className={`nav-item ${location.pathname === item.path ? "active" : ""}`}
          >
            <item.icon size={20} />
            {item.label}
          </Link>
        ))}
      </nav>
      <div className="sidebar-footer">
        <button className="nav-item logout-btn" onClick={logout}>
          <LogOut size={20} />
          Logout
        </button>
      </div>
    </aside>
  );
};

const getNotificationColor = (type) => {
  switch (type) {
    case "NEW_ORDER":
    case "NEW_CUSTOM_ORDER":
      return "#3b82f6";
    case "NEW_RIDE":
      return "#10b981";
    case "PENDING_ORDER_ALERT":
    case "PENDING_RIDE_ALERT":
    case "PENDING_CUSTOM_ORDER_ALERT":
      return "#ef4444";
    case "CHAT_MESSAGE":
      return "#8b5cf6";
    case "BANNER_REQUEST":
      return "#06b6d4";
    case "ACTIVATION_REQUEST":
      return "#f59e0b";
    default:
      return "#64748b";
  }
};

const Topbar = ({ theme, toggleTheme }) => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [showNotifications, setShowNotifications] = useState(false);
  const [activationRequests, setActivationRequests] = useState([]);

  const fetchActivationRequests = async () => {
    try {
      const data = await adminService.getActivationRequests();
      setActivationRequests(
        data.filter((u) => u.isDeleted && u.activationRequested),
      );
    } catch (error) {
    }
  };

  useEffect(() => {
    fetchActivationRequests();
    const interval = setInterval(fetchActivationRequests, 15000);
    return () => clearInterval(interval);
  }, []);

  const { notifications, unseenCount, markAllSeen, markSeen } =
    useAdminNotifications(user, activationRequests);

  const handleToggleNotifications = () => {
    const next = !showNotifications;
    setShowNotifications(next);
    if (next && unseenCount > 0) {
      markAllSeen();
    }
  };

  const handleNotificationClick = (notif) => {
    markSeen(notif.id);
    setShowNotifications(false);
    if (notif.link) {
      navigate(notif.link);
    }
  };

  return (
    <header className="topbar animate-fade-in">
      <div className="page-title">Admin Dashboard</div>
      <div className="topbar-actions">
        <button
          className="icon-btn"
          onClick={toggleTheme}
          aria-label="Toggle Theme"
        >
          {theme === "dark" ? <Sun size={20} /> : <Moon size={20} />}
        </button>

        <div className="notification-menu-wrap">
          <button
            className="icon-btn"
            aria-label="Notifications"
            onClick={handleToggleNotifications}
          >
            <Bell size={20} />
            {unseenCount > 0 && (
              <span
                style={{
                  position: "absolute",
                  top: -2,
                  right: -2,
                  backgroundColor: "#ef4444",
                  color: "white",
                  fontSize: "10px",
                  minWidth: "18px",
                  height: "18px",
                  borderRadius: "50%",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontWeight: "bold",
                  border: "2px solid var(--surface-color)",
                  padding: "0 4px",
                }}
              >
                {unseenCount > 99 ? "99+" : unseenCount}
              </span>
            )}
          </button>

          {showNotifications && (
            <div className="notification-dropdown">
              <div className="notification-dropdown-header">
                <span>Notifications</span>
                {unseenCount > 0 && (
                  <span
                    style={{
                      fontSize: "12px",
                      color: "var(--text-muted)",
                      fontWeight: "normal",
                    }}
                  >
                    {unseenCount} unread
                  </span>
                )}
              </div>
              <div className="notification-dropdown-list">
                {notifications.length > 0 ? (
                  notifications.map((notif) => (
                    <button
                      key={notif.id}
                      type="button"
                      onClick={() => handleNotificationClick(notif)}
                      className={`notification-dropdown-item ${notif.seen ? "" : "unread"}`}
                    >
                      <div
                        style={{
                          display: "flex",
                          alignItems: "center",
                          gap: "8px",
                        }}
                      >
                        {!notif.seen && (
                          <div
                            style={{
                              width: 8,
                              height: 8,
                              borderRadius: "50%",
                              backgroundColor: getNotificationColor(notif.type),
                              flexShrink: 0,
                            }}
                          />
                        )}
                        <span style={{ fontSize: "14px", fontWeight: "600" }}>
                          {notif.title}
                        </span>
                      </div>
                      <span
                        style={{
                          fontSize: "13px",
                          color: "var(--text-muted)",
                          marginLeft: notif.seen ? 0 : "16px",
                          lineHeight: "1.4",
                        }}
                      >
                        {notif.message}
                      </span>
                    </button>
                  ))
                ) : (
                  <div className="notification-dropdown-empty">
                    No notifications yet
                  </div>
                )}
              </div>
            </div>
          )}
        </div>

        <div className="profile-widget">
          <div className="profile-initials">
            {user?.name?.substring(0, 2).toUpperCase() || "AD"}
          </div>
          <span style={{ fontWeight: 500, fontSize: "0.9rem" }}>
            {user?.name || "Admin"}
          </span>
        </div>
      </div>
    </header>
  );
};

const DashboardHome = () => {
  const [statsData, setStatsData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const data = await adminService.getStats();
        setStatsData(data);
      } catch (error) {
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  const stats = [
    {
      title: "Total Revenue",
      value: `PKR ${statsData?.totalRevenue?.toLocaleString() || "0"}`,
      trend: statsData?.trends?.revenue || "+0%",
      isUp: true,
      icon: TrendingUp,
    },
    {
      title: "Active Orders",
      value: statsData?.activeOrders?.toString() || "0",
      trend: statsData?.trends?.orders || "+0%",
      isUp: true,
      icon: ShoppingBag,
    },
    {
      title: "Registered Riders",
      value: statsData?.totalRiders?.toString() || "0",
      trend: statsData?.trends?.riders || "0%",
      isUp: (statsData?.trends?.riders || "").startsWith("+"),
      icon: Bike,
    },
    {
      title: "Active Shops",
      value: statsData?.totalShops?.toString() || "0",
      trend: statsData?.trends?.shops || "+0%",
      isUp: true,
      icon: Store,
    },
    {
      title: "Total Customers",
      value: statsData?.totalCustomers?.toString() || "0",
      trend: statsData?.trends?.customers || "+0%",
      isUp: true,
      icon: Users,
    },
    {
      title: "Total Products",
      value: statsData?.totalProducts?.toString() || "0",
      trend: statsData?.trends?.products || "+0%",
      isUp: true,
      icon: Package,
    },
  ];

  if (loading) {
    return (
      <div className="content-area">
        <div className="table-loader">Loading overview statistics...</div>
      </div>
    );
  }

  return (
    <div className="content-area">
      <div className="stats-grid">
        {stats.map((stat, index) => (
          <div
            key={index}
            className="stat-card"
            style={{ animationDelay: `${index * 100}ms` }}
          >
            <div className="stat-card-header">
              <div className="stat-title">{stat.title}</div>
              <div
                className="stat-icon"
                style={{
                  background: "rgba(59, 130, 246, 0.1)",
                  color: "var(--accent-primary)",
                }}
              >
                <stat.icon size={24} />
              </div>
            </div>
            <div className="stat-value">{stat.value}</div>
            <div
              className={`stat-trend ${stat.isUp ? "trend-up" : "trend-down"}`}
            >
              {stat.isUp ? (
                <TrendingUp size={16} />
              ) : (
                <TrendingDown size={16} />
              )}
              {stat.trend} from last month
            </div>
          </div>
        ))}
      </div>

      <div
        className="glass-panel"
        style={{ padding: "2rem", marginTop: "2rem" }}
      >
        <h2 style={{ marginBottom: "1.5rem", fontSize: "1.25rem" }}>
          System Overview
        </h2>
        <div style={{ color: "var(--text-muted)", lineHeight: "1.6" }}>
          Welcome back! The dashboard is now connected to live business metrics.
          Currently, you have <strong>{statsData?.activeOrders}</strong> active
          orders being processed by
          <strong> {statsData?.totalRiders}</strong> riders across{" "}
          <strong>{statsData?.totalShops}</strong> shops, serving{" "}
          <strong>{statsData?.totalCustomers}</strong> registered customers with
          a catalog of
          <strong> {statsData?.totalProducts}</strong> products. Total platform
          revenue has reached{" "}
          <strong>PKR {statsData?.totalRevenue?.toLocaleString()}</strong>.
        </div>
      </div>
    </div>
  );
};

const PlaceholderComponent = ({ title }) => (
  <div className="content-area">
    <h2>{title} Management</h2>
    <p style={{ marginTop: "1rem", color: "var(--text-muted)" }}>
      This section is currently under development.
    </p>
  </div>
);

const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();

  if (loading) {
    return (
      <div className="loading-screen">
        <div className="loader"></div>
      </div>
    );
  }

  if (!user) {
    return <Navigate to="/login" />;
  }

  return children;
};

function AppContent() {
  const [theme, setTheme] = useState("dark");

  useEffect(() => {
    document.documentElement.setAttribute("data-theme", theme);
  }, [theme]);

  // FCM Configuration validation
  useEffect(() => {
    if (!("Notification" in window)) {
    }
    if (!("serviceWorker" in navigator)) {
    }
  }, []);

  const toggleTheme = () => {
    setTheme((prev) => (prev === "dark" ? "light" : "dark"));
  };

  return (
    <Routes>
      <Route path="/login" element={<Login />} />
      <Route
        path="/*"
        element={
          <ProtectedRoute>
            <div className="layout">
              <Sidebar />
              <main className="main-content">
                <Topbar theme={theme} toggleTheme={toggleTheme} />
                <Routes>
                  <Route path="/" element={<DashboardHome />} />
                  <Route path="/notifications" element={<Notifications />} />
                  <Route path="/chats" element={<Chats />} />
                  <Route path="/cities" element={<Cities />} />
                  <Route path="/orders" element={<Orders />} />
                  <Route path="/custom-orders" element={<CustomOrders />} />
                  <Route path="/rides" element={<Rides />} />
                  <Route path="/products" element={<Products />} />
                  <Route path="/customers" element={<Customers />} />
                  <Route path="/riders" element={<Riders />} />
                  <Route path="/shops" element={<Shops />} />
                  <Route path="/banners" element={<Banners />} />
                  <Route path="/settings" element={<Settings />} />
                </Routes>
              </main>
            </div>
          </ProtectedRoute>
        }
      />
    </Routes>
  );
}

function App() {
  return (
    <AuthProvider>
      <Router>
        <AppContent />
        <Toaster
          position="top-right"
          toastOptions={{
            duration: 3000,
          }}
        />
      </Router>
    </AuthProvider>
  );
}

export default App;
